         goto 291
         endif
      if (INSTRING(1:4).eq.'QCOL') then
         read(INSTRING(5:8),*) QCOL
         goto 291
         endif
      if (INSTRING(1:4).eq.'RCOL') then
         read(INSTRING(5:8),*) RCOL
         goto 291
         endif
      if (INSTRING(1:1).eq.'#') goto 291
      if (INSTRING(1:1).eq.'M') goto 291
      if (INSTRING(1:1).eq.'L') goto 291
      write(*,'(200a)')  '*************************',
