      yind = yin
      if (CHIPNO.eq.05) mr = mr + wfc_zpa(xind,yind,2)
      if (CHIPNO.eq.06) mr = mr + wfc_zpa(xind,yind,1)
      if (CHIPNO.eq.07) mr = mr + hrc_zpa(xind,yind)
      if (CHIPNO.eq.08) mr = mr + wfc3uv_zpa(xind,yind,0)
      if (CHIPNO.eq.09) mr = mr + wfc3ir_zpa(xind,yind)
      if (CHIPNO.eq.98) then
          call xryr2mc_stdgc(xind,yind,mc,FILE_STDGDC)
          mr = mr + mc
          endif
      if (CHIPNO.eq.99) mr=  mr + fits4096_zp(xind,yind,GCFILE)
      qin = qr
      if (xin.lt.XLO) goto 293
      if (xin.gt.XHI) goto 293
      if (yin.lt.YLO) goto 293
      if (yin.gt.YHI) goto 293
      if ( mr.lt.MLO) goto 293
      if ( mr.gt.MHI) goto 293
      if ( qr.lt.QLO) goto 293
      if ( qr.gt.QHI) goto 293
      if ( rr.lt.RLO) goto 293
      if ( rr.gt.RHI) goto 293
      if (DOCTEFIX) then
          call doctefix_ym(yin,zinr,CTE_MAG,CTE_FIX,NCTEs)
          write(78,177) xr,yr,mr,xin,yin,zinr
          yinr = yin
          endif
      zin = mr-ZPU
      if (CHIPNO.ge.1.and.CHIPNO.le.4) then  ! MODIFICATION
         xsingl = xin
         ysingl = yin
         call fixrows(ysingl,ysingl)
         call wfpc2gcK(xsingl,ysingl,
     .                 xsingl,ysingl,CHIPNO)
         xin = xsingl
         yin = ysingl
         endif
      xind = xin
      yind = yin
      if (RDATE.lt.2000) then
         if (CHIPNO.eq.05) call wfc_gcf(xind,yind,xind,yind,2,IFILT)
         if (CHIPNO.eq.06) call wfc_gcf(xind,yind,xind,yind,1,IFILT)
         endif
      if (RDATE.gt.2000) then
         xine = xin
         yine = yin
         if (CHIPNO.eq.5) call wfc_gcf_rdate(xine,yine,
     .                                       xind,yind,2,IFILT,RDATE)
         if (CHIPNO.eq.6) call wfc_gcf_rdate(xine,yine,
     .                                       xind,yind,1,IFILT,RDATE)
         endif
      if (CHIPNO.eq.07) call hrc_gcf(xind,yind,xind,yind,IFILT)
      if (CHIPNO.eq.08) call wfc3uv_gc_meta(xind,yind,IFILT,
     .                                      xind,yind)
      if (CHIPNO.eq.09) call wfc3ir_gcY(xind,yind,xind,yind)
      if (CHIPNO.eq.98) then
          xine = xind
          yine = yind
          call xryr2xcyc_stdgc(xine,yine,xind,yind,FILE_STDGDC)
          endif
      if (CHIPNO.eq.99) call fits4096_gc(xind,yind,xind,yind,0,GCFILE)
      xin = xind
      yin = yind
      NTRY = NTRY + 1
      NSTAR = NSTAR + 1
      if (NSTAR.gt._NSTMAX_) then
         print*,'NOT ENOUGH MEMORY TO CONTAIN ALL STARS'
         print*,'  thus far NSTAR: ',NSTAR
         print*,'         maxposs: ',_NSTMAX_
         print*,'       (_NSTMAX_) '
         stop
         endif
      xraw(NSTAR) = xinr
      yraw(NSTAR) = yinr
      zraw(NSTAR) = mr
      xloc(NSTAR) = xin
      yloc(NSTAR) = yin
      zloc(NSTAR) = zin
      qloc(NSTAR) = qr
      sraw(NSTAR) = INSTRING(1:129)
 
      xr = AGN(NIM)*(xin-XoN(NIM))+BGN(NIM)*(yin-YoN(NIM))+WoN(NIM)
      yr = CGN(NIM)*(xin-XoN(NIM))+DGN(NIM)*(yin-YoN(NIM))+ZoN(NIM)
      xlu = xr
      ylu = yr
      xmap(NSTAR) = xr
      ymap(NSTAR) = yr
      xmap(NSTAR) = xlu
      ymap(NSTAR) = ylu
      if (NSTAR.eq.NSTAR/1000*1000)
     .write( *,'(2i7,1x,20f10.3)') NIM,NSTAR,
     .             xin,yin,xlu,ylu,xr,yr,
     .             xloc(NSTAR),yloc(NSTAR),zloc(NSTAR)
      goto 293
 294  continue
 300  continue
      close(47)
