      write(*,37) '   Xh: ',minarr(xloc,NSTARs), maxarr(xloc,NSTARs)
      write(*,37) '   Yh: ',minarr(yloc,NSTARs), maxarr(yloc,NSTARs)
      write(*,37) '   Zh: ',minarr(zloc,NSTARs), maxarr(zloc,NSTARs)
      write(*,* ) '   Fh: ',CHIPNO,IFILT
      xmin = minarr(xloc,NSTARs)
      ymin = minarr(yloc,NSTARs)
      xmax = maxarr(xloc,NSTARs)
      ymax = maxarr(yloc,NSTARs)
      print*,'ACT:  x: ',xmin,xmax
      print*,'ACT:  y: ',ymin,ymax
      print*,'_HASHDIM_',_HASHDIM_
      if (xmax.lt.xmin+_HASHDIM_) xmax = xmin+_HASHDIM_
      if (ymax.lt.ymin+_HASHDIM_) ymax = ymin+_HASHDIM_
      print*,'FIX:  x: ',xmin,xmax
      print*,'FIX:  y: ',ymin,ymax
 
c--------------------------------------------------
c
c the hash table makes it possible to quickly find
c stars in the long list. w/o it, it could take a
c ridiculously long time!  the hash table orders stars
c in two dimensions, so that we must only search a few
c bins for each possible cross-id
c
      print*,'THROW THE STARS INTO THE HASH TABLE...  NSTARs: ',NSTARs
      do ihx = 1, _HASHDIM_
      do ihy = 1, _HASHDIM_
         nash(ihx,ihy)   = 0
         enddo
         enddo
 
      print*,'  NSTARs: ',NSTARs
      print*,'xmin/max: ',xmin,xmax
      print*,'ymin/max: ',ymin,ymax
      do NSTAR = 1, NSTARs
         ihx = 1 + (_HASHDIM_-1)*(xloc(NSTAR)-xmin)/(xmax-xmin)
         ihy = 1 + (_HASHDIM_-1)*(yloc(NSTAR)-ymin)/(ymax-ymin)
         if (ihx.lt.1) ihx = 1
         if (ihy.lt.1) ihy = 1
         if (ihx.gt._HASHDIM_) ihx = _HASHDIM_
         if (ihy.gt._HASHDIM_) ihy = _HASHDIM_
         nash(ihx,ihy) = nash(ihx,ihy) + 1
         if (nash(ihx,ihy).gt._HASHDEP_) nash(ihx,ihy) = _HASHDEP_
         if (nash(ihx,ihy).gt._HASHDEP_.and.
     .       ihx.gt.1.and.ihy.gt.1) then
            print*,'           '
            print*,'_HASHDEP_: ',_HASHDEP_
            NSTARu = hash(ihx,ihy,nash(ihx,ihy))
            print*,'    NSTAR: ',NSTAR, xloc(NSTAR) ,
     .                                  yloc(NSTAR) ,zloc(NSTAR)
            print*,'     NASH: ',NSTARu,xloc(NSTARu),
     .                                  yloc(NSTARu),zloc(NSTARu)
            print*,'      ihx: ',ihx,xmin,xmax
            print*,'      ihy: ',ihy,ymin,ymax
            print*,'           '
            print*,' (the hash table is overfull!) '
            print*,' (you can avoid this by upping _HASHDEP_) '
            print*,'           '
            print*,'           '
            stop
            endif
         hash(ihx,ihy,nash(ihx,ihy)) = NSTAR
 88      continue
         enddo
      do ihx = 1, 100
         hhist(ihx) = 0
         enddo
      do ihx = 1, _HASHDIM_
      do ihy = 1, _HASHDIM_
         hhist(nash(ihx,ihy)+1) = hhist(nash(ihx,ihy)+1)+1
         enddo
         enddo
      nhh = 0
      print*,'HASH REPORT: ',NSTARs
      do ihx = 1, 3!_HASHDEP_+1
         write(*,'(i3,1x,i6)') ihx-1,hhist(ihx)
         nhh = hhist(ihx) + 1
         enddo
      print*,'        TOT: ',nhh
 
      NFND = 0
 
      print*,'BLINK: xmin/max: ',xmin,xmax
      print*,'BLINK: ymin/max: ',ymin,ymax
 
 
c------------------------------------------------------
c
c following are preparations for outputting the LNK file
c
      call dirstrip(FILE,FILEDIR,FILEPRE,FILESUFF)
 
 
      if (DOARTFILE) then
