         write(*,'(''ARTFILE: '',80a)') ARTFILE
         open(51,file=ARTFILE,status='unknown')
         endif
      if (DOLNKFILE) then
         write(LNKFILE,'(''LNK.'',i3.3)') NIM
         if (DOLNKSTEM) then
            LNKFILE = 'NULL'
            K1 = 1
            do k = 1, 70, 1
               if (FILE(k:k).eq.'/') K1 = k+1
               enddo
            K2 = -1
            do k = K1, 76, 1
               if (FILE(k:k).eq.'.') K2 = k-1
               enddo
            if (K2.eq.-1) then
               do k = 76, K1, -1
                  if (FILE(k:k).eq.' ') K2 = k-1
                  enddo
               endif
            if (K2.eq.-1) then
                print*,' '
