                endif
            LNKFILE = FILE(K1:K2) // '.lnk'
            endif
         write(*,'(''LNKFILE: '',80a)') LNKFILE
         open(50,file=LNKFILE,status='unknown')
         endif
      do NPK = 1, NPKs
         xlu = AG*(pkxr(NPK)-Wo)+BG*(pkyr(NPK)-Zo) + Xo
         ylu = CG*(pkxr(NPK)-Wo)+DG*(pkyr(NPK)-Zo) + Yo
         xlux = xlu
         ylux = ylu
         xlur = xlu
         ylur = ylu
         if (CHIPNO.eq.5) then
            call wfc_cgf(xlux,ylux,xlur,ylur,0,IFILT)
            endif
         if (CHIPNO.eq.7) then
            call hrc_cgf(xlux,ylux,xlur,ylur,IFILT)
            endif
         if (CHIPNO.eq.08) call wfc3uv_cg_meta(xlux,ylux,0,IFILT,
