c        MATCHMR(NPK,NIM) = 0.0
c        MATCHXE(NPK,NIM) = 0.0
c        MATCHYE(NPK,NIM) = 0.0
         ihxc = 1 + (_HASHDIM_-1)*(xlu-xmin)/(xmax-xmin)
         ihyc = 1 + (_HASHDIM_-1)*(ylu-ymin)/(ymax-ymin)
         NSTARu = 0
         if (xlu.lt.xmin-5.or.xlu.gt.xmax+5.or.
