             MATCHMT(NPK,NIM) = zloc(NSTARu)
             MATCHQT(NPK,NIM) = qloc(NSTARu)
c            MATCHXC(NPK,NIM) = xloc(NSTARu)
c            MATCHYC(NPK,NIM) = yloc(NSTARu)
c            MATCHMR(NPK,NIM) = zraw(NSTARu)
             MATCHXR(NPK,NIM) = xraw(NSTARu)
             MATCHYR(NPK,NIM) = yraw(NSTARu)
c            MATCHDD(NPK,NIM) = dmin
             NFND = NFND + 1
             pkf(NPK) = pkf(NPK) + 1
             endif
 333     continue
         if (DOARTFILE) then
             mr = pkmr(NPK)
             xind = xlur
             yind = ylur
             if (CHIPNO.eq.05) mr = mr - wfc_zpa(xind,yind,2)
             if (CHIPNO.eq.06) mr = mr - wfc_zpa(xind,yind,1)
             if (CHIPNO.eq.07) mr = mr - hrc_zpa(xind,yind)
             if (CHIPNO.eq.08) mr = mr - wfc3uv_zpa(xind,yind,0)
             if (CHIPNO.eq.09) mr = mr - wfc3ir_zpa(xind,yind)
             if (CHIPNO.eq.98) then
                 call xryr2mc_stdgc(xind,yind,mc,FILE_STDGDC)
                 mr = mr - mc
                 endif
             if (CHIPNO.eq.99) mr = mr - fits4096_zp(xind,yind,GCFILE)
             write(51,151) dclip(xlur,-999.0d0,9999.9d0),
