             ix = pki(NPK)
             iy = pkj(NPK)
             if (ix.ge.1.and.ix.le._PIXDIM_.and.
     .           iy.ge.1.and.iy.le._PIXDIM_) then
                 pkp(NPK) = pk_cvg(ix,iy)
                 endif
             enddo
          endif
 
      print*,'OUTPUT FILEOUT: ',FILEOUT(1:20)
