c
         dop = NPK.eq.NPK/1000*1000
         if (dop) print*,'NPK: ',NPK,NPKs,pkx(NPK),pky(NPK)
         NIMf = 0
         do NIM = 1, NIMs
            xl(NIM) = 0.
            yl(NIM) = 0.
            ml(NIM) = 0.
            if (MATCHUP(NPK,NIM).gt.0) then
               NIMf = NIMf + 1
               xl(NIMf) = MATCHXT(NPK,NIM)
               yl(NIMf) = MATCHYT(NPK,NIM)
               ml(NIMf) = MATCHMT(NPK,NIM)
               ql(NIMf) = MATCHQT(NPK,NIM)
               el(NIMf) = 0.02
               wl(NIMf) = 1
               if (dop) write(*,'(2i4,10f10.4)')
     .                        NIM,NIMf,xl(NIMf),yl(NIMf),ml(NIMf),
