      do NARG = 1, NARGs
         call getarg(NARG,INSTRING)
         write(25,'(''# ARG'',i3.3,1x,80a)') NARG,INSTRING(1:80)
         enddo
      write(25,'(''#-------------------------'')')
      do NARG = 1, INPLINEs
         write(25,'(''# INP'',a200)') INPLINE(NARG)
         enddo
      write(25,'(''#-------------------------'')')
      close(25)
 
      stop
 
 
 988  continue
      print*,'ERROR OPENING MAT FILE'
      stop
 
 989  continue
      print*,'no NIM=0 line!'
      stop
 
 999  continue
      print*,'INTERNAL READ ERROR...'
      stop
 
      end
 
                                              
