c      logical islinux, islinux_var
c
c      islinux_var = islinux()
c
c      islinux_var = islinux()
c
c      stop
c      end
 
 
      logical function islinux()
      implicit none
 
      logical done
      logical islinux_save
 
      integer i
      data i/0/
      data islinux_save/.true./
 
      common /islinux_/i,islinux_save
 
      byte    b(2)
      equivalence(i,b)
 
      if (i.eq.1) goto 1
 
      i = 1
      islinux_save = .false.
      if (b(1).eq.1) islinux_save = .true.
 
    1 islinux = islinux_save
      return
      end
 
 
 
                                              
