c---------------------------------------------------------
c
c this corrections the solution for a small (0.02-pixel)
c on-axis skew (see skew correction)
c --> I moved the correction into wfc3uv_gc_meta_k so
c     that it would go into everything (as well as the
c     inverse)
c --> Here's the correction.  It adds 0.01 pixel to x
c     and takes off 0.01 pixel from y.
c
c      xc = xc + (xc-2048)/2048*0.01 ! skew correction
c      yc = yc - (yc-2048)/2048*0.01
c
c---------------------------------------------------------
 
 
c--------------------------------------------------------------
c
c this file contains three subroutines:
c
c   1) subroutine wfc3uv_gc(xr,yr,chip,filter,xc,yc)
c
c   2) subroutine wfc3uv_gc_meta_k(xr,yr,chip,filter,xc,yc)
c
c   3) subroutine wfc3uv_gc_meta(xr,yr,filter,xc,yc)
c
c--------------------------------------------------------------
 
 
