c
c scale 0.0497248
c
 
c------------------------------------
c
c HERE IS THE LATEST WFC DISTORTION CORRECTION
c
c I have not put too much effort into documenting this
c routine, so if you have any questions at all, don't
c hesitate to e-mail me.
c
c
c    Jay Andeson
c    jay@eeyore.rice.edu
c    Jun 03, 2004
c
c------------------------------------
 
c----------------------------
c
c k = chip number
c     1 = WFC1 top chip [4]
c     2 = WFC2 bot chip [1]
c     0 = equivalent to 2
c
c     if k==2 and yi>2048, then assume that it is
c       in an abutted system with y in the top chip
c       given by (yi-2048)
c
c----------------------------------
 
c----------------------------
c
c f = filter number
c
c  0) use no table correction, only the polynomial
c  1) F435W
c  2) F475W
c  3) F555W
c  4) F606W
c  5) F814W
c  6) F850L
c  7) F625W
c  8) F658N
c  9) F775W
c 10) F660N
c 11) F502N
c 12) F550M
c
c----------------------------
 
 
      subroutine wfc_gcf(xi,yi,xo,yo,ki,fi)
      implicit none
      real*8  xi, yi   ! input raw (x,y) position in chip
      real*8  xo, yo   ! output distortion corrected position in meta system
      integer ki       ! chip #:  ki=1 WFC1 (top chip)   ki=2 WFC2 (bot chip)
      integer fi       ! filt #:  1=F435W 2=F475W 3=F555W 4=F606W 5=F814W
                       !          0=NONE ---> so, no table correction
 
      real*8  xu, yu
      integer ku, fu
      real*8  fx, fy
      real*8 t(15)
 
 
      real*8 tab1xx_fn
      real*8 tab1yy_fn
      real*8 tab2xx_fn
      real*8 tab2yy_fn
 
      real*8 poly1x(15), poly1y(15) ! TOP CHIP WFC1
      real*8 poly2x(15), poly2y(15) ! BOT CHIP WFC2
 
      real*8 dxpoly, dypoly
      real*8 dxlut,  dylut
 
      integer NORD
 
      real*8  rx, ry
      integer ix, iy
      real*8  dx, dy
 
 
c----------------------------------------------------------
c in LINUX, the data statements have to come after the
c common statements, for some bizarre reason
c
      common /polyy/poly1x,poly1y,poly2x,poly2y
      data poly1x /
     .      4.222858,-25.810972,  7.522745, 35.110044,-15.458679,
     .      2.224611, -3.997423, -0.461412, -1.137435,  0.069899,
     .      0.365157,  0.297704,  0.451025, -0.059556,  0.164580/
      data poly1y /
     .   2090.829009,166.636444,-22.581991, -9.224829, 11.854841,
     .     -9.812475,  0.450533, -1.922356, -0.151181, -0.408813,
     .     -0.294261, -0.302678, -0.414122,  0.101310, -0.188003/
      data poly2x /
     .     -0.013903,  0.115885, -0.014278, 35.845661,-10.955353,
     .      2.264019, -4.018862, -0.189312, -1.135375,  0.008529,
     .      0.419362,  0.099082,  0.167527, -0.036017, -0.000001/
      data poly2y /
     .      0.023567,141.245503, 11.904442, -4.966731, 12.417648,
     .     -7.488638,  0.463892, -2.239110, -0.249694, -0.464881,
     .     -0.258344, -0.022357, -0.105517, -0.050072, -0.031641/
 
 
      xu = xi
      call fixcoll(xi,xu)
      yu = yi
      ku = abs(ki)
      fu = fi
      if (ki.eq.0) ku = 2
 
      if (yu.gt.2048.and.ki.eq.2) then ! in this case, we're dealing with
         yu = yu-2048.0                ! an abutted-chip system based on the
         ku = 1                        ! bot chip, but really in top chip (WFC1)
         endif
 
      if (ku.ne.1.and.ku.ne.2) then
          print*,'wfc_gc:  invalid chip number'
          print*,'    ku:  ',ku
          stop
          endif
 
      fx = (xu-2048.0)/2048.0
      fy = (yu-1024.0)/1024.0
 
      t(01) = 1.0
 
      t(02) = fx
      t(03) = fy
 
      t(04) = fx*fx
      t(05) = fx*fy
      t(06) = fy*fy
 
      t(07) = fx*fx*fx
      t(08) = fx*fx*fy
      t(09) = fx*fy*fy
      t(10) = fy*fy*fy
 
      t(11) = fx*fx*fx*fx
      t(12) = fx*fx*fx*fy
      t(13) = fx*fx*fy*fy
      t(14) = fx*fy*fy*fy
      t(15) = fy*fy*fy*fy
 
      dxpoly = 0.0
      dypoly = 0.0
      if (ku.eq.1) then
         do NORD = 01, 15
            dxpoly = dxpoly + t(NORD)*poly1x(NORD)
            dypoly = dypoly + t(NORD)*poly1y(NORD)
            enddo
         endif
      if (ku.eq.2) then
         do NORD = 01, 15
            dxpoly = dxpoly + t(NORD)*poly2x(NORD)
            dypoly = dypoly + t(NORD)*poly2y(NORD)
            enddo
         endif
 
 
      rx = 1 + xu/64                ! the "real" location within the table
      ry = 1 + yu/64
      if (rx.lt.01) rx = 01.000     ! don't let it go off the table
      if (ry.lt.01) ry = 01.000
      if (rx.ge.65) rx = 64.999
      if (ry.ge.33) ry = 32.999
      ix = int(rx)
      iy = int(ry)
      dx = rx-ix
      dy = ry-iy
 
      dxlut = 0.
      dylut = 0.
 
      if (ku.eq.1.and.fu.ge.1.and.fu.le.12) then ! top chip
         dxlut = (1-dx)*(1-dy)*tab1xx_fn(ix  ,iy  ,fu)
     .         + (1-dx)*( dy )*tab1xx_fn(ix  ,iy+1,fu)
     .         + ( dx )*(1-dy)*tab1xx_fn(ix+1,iy  ,fu)
     .         + ( dx )*( dy )*tab1xx_fn(ix+1,iy+1,fu)
         dylut = (1-dx)*(1-dy)*tab1yy_fn(ix  ,iy  ,fu)
     .         + (1-dx)*( dy )*tab1yy_fn(ix  ,iy+1,fu)
     .         + ( dx )*(1-dy)*tab1yy_fn(ix+1,iy  ,fu)
     .         + ( dx )*( dy )*tab1yy_fn(ix+1,iy+1,fu)
         endif
 
      if (ku.eq.2.and.fu.ge.1.and.fu.le.12) then ! bot chip
         dxlut = (1-dx)*(1-dy)*tab2xx_fn(ix  ,iy  ,fu)
     .         + (1-dx)*( dy )*tab2xx_fn(ix  ,iy+1,fu)
     .         + ( dx )*(1-dy)*tab2xx_fn(ix+1,iy  ,fu)
     .         + ( dx )*( dy )*tab2xx_fn(ix+1,iy+1,fu)
         dylut = (1-dx)*(1-dy)*tab2yy_fn(ix  ,iy  ,fu)
     .         + (1-dx)*( dy )*tab2yy_fn(ix  ,iy+1,fu)
     .         + ( dx )*(1-dy)*tab2yy_fn(ix+1,iy  ,fu)
     .         + ( dx )*( dy )*tab2yy_fn(ix+1,iy+1,fu)
         endif
 
      xo = xu + dxpoly + dxlut
      yo = yu + dypoly + dylut
 
      return
      end
 
 
 
 
 
