      real*8 function tab1xx_fn(i,j,g)
      implicit none
      integer i,j,g
      integer*2 wwtabx1(12,33,65)
      common /wwtabx1_/wwtabx1
 
      tab1xx_fn = wwtabx1(g,j,i)/1000.0
      return
      end
 
      real*8 function tab1yy_fn(i,j,g)
      implicit none
      integer i,j,g
      integer*2 wwtaby1(12,33,65)
      common /wwtaby1_/wwtaby1
 
      tab1yy_fn = wwtaby1(g,j,i)/1000.0
      if (g.eq.8.and.j.eq.1) tab1yy_fn = tab1yy_fn+0.01
 
      return
      end
 
      real*8 function tab2xx_fn(i,j,g)
      implicit none
      integer i,j,g
