c****                                         
c**** #include "/user/jayander/FORTRAN/GC/ACSWFC/wfc_gcf_rdate.f"
c****                                         
c*********************************************
                                              
 
c----------------------------
c
c this program is a wrapper for wfc_gcf,
c which computes the correction using the
c standard procedure, then it implements
c the time-dependent skew correction
c
c----------------------------
 
 
      subroutine wfc_gcf_rdate(xi,yi,xo,yo,ki,fi,rdate)
      implicit none
      real*8  xi, yi   ! input raw (x,y) position in chip
      real*8  xo, yo   ! output distortion corrected position in meta system
      integer ki       ! chip #:  ki=1 WFC1 (top chip)   ki=2 WFC2 (bot chip)
      integer fi       ! filt #:  1=F435W 2=F475W 3=F555W 4=F606W 5=F814W
                       !          0=NONE ---> so, no table correction
      real rdate       ! in units of years 2000.0 is 01jan2000
                       !                   2006.5 is 30jun2006, etc
 
      real rdateu
      real*8 xtemp, ytemp
      real alpha, beta
      real fx, fy
 
      rdateu = rdate
      if (rdate.eq.2002.0) then
         call wfc_gcf(xi,yi,xo,yo,ki,fi)
         return
         endif
 
      if (rdate.lt.2002.0.or.rdate.gt.2015) then
         print*,' problem in wfc_gcf_rdate: '
         print*,' '
         print*,'                    rdate: ',rdate
         print*,' '
         print*,' ... should be between 2002 and 2015.'
         print*,' '
         stop
         endif
 
      if (rdateu.gt.2007.5) rdateu = rdateu - 2.4  ! ACS was off for about 2 years + 4 months
 
c
c Compute the coefficients for the appropriate date; note
c that alpha and beta are pretty much zero at 2002.0, no surprise
c there, since that's when the linear terms of the standard
c solution were constrained.
c
      alpha =  0.095 + 0.090*(rdateu-2004.5)/2.5
      beta  = -0.029 - 0.030*(rdateu-2004.5)/2.5
 
c
c call the original wfc_gcf to get the standard correction
c
      call wfc_gcf(xi,yi,xtemp,ytemp,ki,fi)
 
c
c compute the scaled mapping of the frame (note we use
c distortion corrected coords!)
c
      fx = (xtemp-2048)/2048
      fy = (ytemp-2048)/2048
 
 
c
c implement the correction
c
      xo = xtemp + beta*fx + alpha*fy
      yo = ytemp - beta*fy + alpha*fx
 
      return
      end
 
                                              
c*********************************************
c****                                         
c**** #include "/user/jayander/FORTRAN/GC/ACSWFC/wfc_cgf.f"
c****                                         
c*********************************************
                                              
 
c----------------------------------------
c
c this will perform the inverse
c distortion correction...
c
      subroutine wfc_cgf(xc,yc,xr,yr,kin,f)
      implicit none
      real*8 xc,yc
      real*8 xr,yr
      integer kin, f
 
      integer k
      real*8 xt,yt
 
      real*8 dx, dy, dd
      integer NIT
      real*8 xr1, yr1
      real*8 xr2, yr2
 
      k = kin
 
      xr1 = xc
      yr1 = yc
      NIT = 0
 1    continue
      NIT = NIT + 1
      call wfc_gcf(xr1,yr1,xt,yt,-1,f)
      dx = xc-xt
      dy = yc-yt
      dd = sqrt(dx**2+dy**2)
      xr1 = xr1 + (xc-xt)*0.5
      yr1 = yr1 + (yc-yt)*0.5
      if (dd.gt.0.001.and.NIT.lt.99) goto 1
 11   continue
 
 
      xr2 = xc
      yr2 = yc
      NIT = 0
 2    continue
      NIT = NIT + 1
      call wfc_gcf(xr2,yr2,xt,yt,-2,f)
      dx = xc-xt
      dy = yc-yt
      dd = sqrt(dx**2+dy**2)
      xr2 = xr2 + (xc-xt)*0.5
      yr2 = yr2 + (yc-yt)*0.5
c     if (yr2.gt.2048) yr2 = 2048
      if (dd.gt.0.001.and.NIT.lt.99) goto 2
 22   continue
 
 
      if (k.eq.1)  then
         xr = xr1
         yr = yr1
         return
         endif
      if (k.eq.2)  then
         xr = xr2
         yr = yr2
         return
         endif
      if (k.le.0) then
         if (yr1.gt.0001) then
             xr = xr1
             yr = yr1+2048
             if (xr.lt.-0500) xr =  -500.0
             if (xr.gt.+5000) xr =  5000.0
             if (yr.lt.-0500) yr =  -500.0
             if (yr.gt.+5000) yr =  5000.0
             return
             endif
         if (yr2.lt.2048) then
             xr = xr2
             yr = yr2
             if (xr.lt.-0500) xr =  -500.0
             if (xr.gt.+5000) xr =  5000.0
             if (yr.lt.-0500) yr =  -500.0
             if (yr.gt.+5000) yr =  5000.0
             return
             endif
         if (yr2.ge.2048.and.yr1.le.0001.and.k.eq.0) then
             xr = -1
             yr = -1
             return
             endif
         if (yr2.ge.2048.and.yr1.le.0001.and.k.eq.-1) then
             xr =  xr2
             yr = 2048
             return
             endif
         xr = -1
         yr = -1
         endif
 
 
 
      return
      end
 
 
 
                                              
