c 0512   0.031  0.022  0.013  0.005 -0.003 -0.011 -0.018 -0.025 -0.032 -0.038 -0.044 -0.050 -0.055 -0.061 -0.066 -0.071
c 0256   0.026  0.017  0.008  0.000 -0.008 -0.016 -0.023 -0.030 -0.037 -0.043 -0.049 -0.055 -0.060 -0.066 -0.071 -0.075
c 0000   0.021  0.012  0.004 -0.005 -0.013 -0.020 -0.028 -0.035 -0.041 -0.048 -0.054 -0.059 -0.065 -0.070 -0.075 -0.080
c
c
c AVG: 0.0000
c
c----------------------------------------------------------------------------------------
c
c this is the photometric correction for the ACS/WFC camera
c
c this corrects an observed magnitude as measured by aperture or
c psf-fitting photometry for the fact that the area subtended by
c each pixel varies because of distortion and the flat fields have
c been constructed to conserve surfact brightness and not flux.
c
c this correction should be ADDED to a magnitude to correct
c it for the pixel area
c
c   mcorr = mraw + wfc_zpa()
c
c
      real function wfc_zpa(x,y,k)
      implicit none
 
      real*8 x, y
      integer k
 
      integer i, j
      real*8 pixarea_wfc
      real*8 pa
 
      if (k.eq.0) then
         i = x
         j = y
         endif
      if (k.eq.1) then
         i = x
         j = y+2048
         endif
      if (k.eq.2) then
         i = x
         j = y
         endif
 
      pa = pixarea_wfc(i,j)
      wfc_zpa = -2.5*log10(pa)  ! I have found experimentally
                                 ! that this is the right sign to
                                 ! use
 
      wfc_zpa = wfc_zpa - 0.03018
 
      return
      end
 
 
 
 
c---------------------------------------------
c
c routine to determine the area on the sky for a given pixel,
c using just the polynomials
c
      real*8 function pixarea_wfc(i,j)
      implicit none
 
      integer i,j
 
      real fx, fy
 
      real dxdx, dxdy
      real dydx, dydy
      real dxdx0,dxdy0
      real dydx0,dydy0
 
 
c
c in LINUX you need to do this to make sure
c that the variables stay in memory
c
      real poly1x(15), poly1y(15) ! TOP CHIP WFC1
      real poly2x(15), poly2y(15) ! BOT CHIP WFC2
