c-----------------------------------
c
c this FORTRAN SUBROUTINE performs the filter-dependent
c HRC distortion correction
c
c (x ,y ) = the input position (real*8)
c (xx,yy) = the output position (real*8)
c
c       f = the filter number for look-up table correction
c           0 = (only polynomial solution)
c           1 = F220W    6 = F606W
c           2 = F330W    7 = F625W
c           3 = F435W    8 = F775W
c           4 = F475W    9 = F814W
c           5 = F555W   10 = F850LP
c
      subroutine hrc_gcf(x,y,xx,yy,f)
      implicit none
 
      real*8  x,  y  ! raw position
      real*8 xx, yy  ! distortion-corrected position
      integer f
 
      real*8 xh, yh
      real dx, dy, rtab
 
      real htabx(10,65,65)
      real htaby(10,65,65)
      common /htabx_/htabx
      common /htaby_/htaby
 
      xh = x
      yh = y
      call hrc_gc(xh,yh,xx,yy)  ! this is the filter-independent solution
      if (f.eq.0) return                  ! (no lookup table)
 
      dx = rtab(xh,yh,f,htabx)
      dy = rtab(xh,yh,f,htaby)
      xx = xx + dx
      yy = yy + dy
 
      return
      end
 
c----------------------------------------
c
c 2-d table interpolation
c
      real function rtab(x,y,f,tab)
      implicit none
 
      integer f
      real*8 x, y
      real   tab(10,65,65)
 
      real rx, ry
      integer ix, iy
      real fx, fy
 
      rtab = 0.
      if (f.lt.1.or.f.gt.10) return
 
      rx = 1 + (x/1024)*64
      ry = 1 + (y/1024)*64
      if (rx.lt.01) rx = 01
      if (ry.lt.01) ry = 01
      if (rx.gt.65) rx = 64.99
      if (ry.gt.65) ry = 64.99
      ix = int(rx)
      iy = int(ry)
      if (ix.lt.01) ix = 01
      if (iy.lt.01) iy = 01
      if (ix.gt.64) ix = 64
      if (iy.gt.64) iy = 64
      fx = rx-ix
      fy = ry-iy
      rtab =  (1-fx)*(1-fy)*tab(f,iy  ,ix  )
     .      + (1-fx)*( fy )*tab(f,iy+1,ix  )
     .      + ( fx )*(1-fy)*tab(f,iy  ,ix+1)
     .      + ( fx )*( fy )*tab(f,iy+1,ix+1)
 
      return
      end
 
 
 
 
c---------------------------------------------------
c
c this performs the polynomial portion of the
c solution (based on the polynomial found for F475W)
c
      subroutine hrc_gc(x,y,xx,yy)
      implicit none
 
      real*8  x,  y
      real*8 xx, yy
 
      real fx, fy
 
      integer i
 
      real polyx(15)
      real polyy(15)
      real polyr(15)
 
c
c in LINUX you need to do this to make sure
c that the variables stay in memory
c
      common /qq/ polyx,polyy
 
 
      logical first
      common /qqq/first
      data first / .true. /
 
      data polyx/
     .   0.000000,  0.000000,  0.000000, -0.864121,  2.355129,
     .  -0.183590,  0.009942,  0.000208,  0.051272,  0.001016,
     .   0.017420, -0.140388, -0.099512,  0.002582,  0.002776/
 
      data polyy/
     .   0.000000, 51.845219,-62.457410,  0.361129, -0.380593,
     .   2.622087,  0.053201,  0.034940, -0.072759,  0.067124,
     .   0.026491, -0.095819,  0.047346, -0.029614, -0.070042/
 
 
      xx = x
      yy = y
 
      fx = (x-512)/512.0
      fy = (y-512)/512.0
 
 
      polyr(01) = 1.0
      polyr(02) = fx
      polyr(03) = fy
      polyr(04) = fx*fx
      polyr(05) = fx*fy
      polyr(06) = fy*fy
      polyr(07) = fx*fx*fx
      polyr(08) = fx*fx*fy
      polyr(09) = fx*fy*fy
      polyr(10) = fy*fy*fy
      polyr(11) = fx*fx*fx*fx
      polyr(12) = fx*fx*fx*fy
      polyr(13) = fx*fx*fy*fy
      polyr(14) = fx*fy*fy*fy
      polyr(15) = fy*fy*fy*fy
 
 
      xx = x
      yy = y
      do i = 2, 15
         xx = xx + polyx(i)*polyr(i)
         yy = yy + polyy(i)*polyr(i)
         enddo
 
      return
      end
 
 
 
 
