c--------------------------------------------
c
c this performs the inverse HRC distortion correction
c
      subroutine hrc_cgf(xx,yy,x,y,ifilt)
      implicit none
 
      real*8 xx,yy
      real*8  x, y
      integer ifilt
      real*8  xe, ye
      real*8 xxe,yye
      real   dd
 
      integer NIT
 
 
c      if (xx.lt.-200.or.xx.gt.1200.or.
c     .    yy.lt.-200.or.yy.gt.1200)  continue
 
      xe = xx
      ye = yy
      do NIT = 01,25
         call hrc_gcf(xe,ye,xxe,yye,ifilt)
         xe = xe + (xx-xxe)*0.90
         ye = ye + (yy-yye)*0.90
         dd = sqrt((xx-xxe)**2+(yy-yye)**2)
         x = xe
         y = ye
         if (dd.lt.0.001) return
         enddo
 
      return
      end
 
                                              
