c----------------------------------------
c
c this routine will return the photometric correction
c that will account for the fact that the flat-fields
c have been constructed to preserve surface brightness
c rather than flux; photometry wants to measure flux
c so we must multiply by the pixel area
c
c this correction should be ADDED to an instrumental
c magnitude measured in a raw image:
c
c
c mcor = mraw + hrc_zpa(x,y)
c
c
      real function hrc_zpa(x,y)
      implicit none
 
      real*8 x, y
      integer i, j
      real*8 pixarea
 
      i = x
      j = y
 
      hrc_zpa = -2.5*log10(pixarea(i,j))  ! I have found experimentally
                                          ! that this is the right sign to
                                          ! use
 
      return
      end
 
 
 
 
 
      real*8 function pixarea(i,j)
      implicit none
 
      integer i,j
 
      real fx, fy
 
      real dxdx, dxdy
      real dydx, dydy
      real dxdx0,dxdy0
      real dydx0,dydy0
 
 
c
c in LINUX you need to do this to make sure
c that the variables stay in memory
c
      real polyx(15)
      real polyy(15)
      common /pareaq/ polyx,polyy
      data polyx/
     .  -0.000180,512.000000,  0.000000, -0.864121,  2.355129,
     .  -0.183590,  0.009942,  0.000208,  0.051272,  0.001016,
     .   0.017420, -0.140388, -0.099512,  0.002582,  0.002776/
 
      data polyy/
     .   0.013041, 51.847919,449.539581,  0.361129, -0.380593,
     .   2.622087,  0.053201,  0.034940, -0.072759,  0.067124,
     .   0.026491, -0.095819,  0.047346, -0.029614, -0.070042/
 
 
      fx = (i-512.0)/512.0
      fy = (j-512.0)/512.0
 
      dxdx = 1*polyx(02)
     .     + 2*polyx(04)*fx
     .     + 1*polyx(05)*fy
     .     + 3*polyx(07)*fx*fx
     .     + 2*polyx(08)*fx*fy
     .     + 1*polyx(09)*fy*fy
     .     + 4*polyx(11)*fx*fx*fx
     .     + 3*polyx(12)*fx*fx*fy
     .     + 2*polyx(13)*fx*fy*fy
     .     + 1*polyx(14)*fy*fy*fy
      dydx = 1*polyy(02)
     .     + 2*polyy(04)*fx
     .     + 1*polyy(05)*fy
     .     + 3*polyy(07)*fx*fx
     .     + 2*polyy(08)*fx*fy
     .     + 1*polyy(09)*fy*fy
     .     + 4*polyy(11)*fx*fx*fx
     .     + 3*polyy(12)*fx*fx*fy
     .     + 2*polyy(13)*fx*fy*fy
     .     + 1*polyy(14)*fy*fy*fy
      dxdy = 1*polyx(03)
     .     + 2*polyx(06)*fy
     .     + 1*polyx(05)*fx
     .     + 3*polyx(10)*fy*fy
     .     + 2*polyx(09)*fx*fy
     .     + 1*polyx(08)*fx*fx
     .     + 4*polyx(15)*fy*fy*fy
     .     + 3*polyx(14)*fx*fy*fy
     .     + 2*polyx(13)*fx*fx*fy
     .     + 1*polyx(12)*fx*fx*fx
      dydy = 1*polyy(03)
     .     + 2*polyy(06)*fy
     .     + 1*polyy(05)*fx
     .     + 3*polyy(10)*fy*fy
     .     + 2*polyy(09)*fx*fy
     .     + 1*polyy(08)*fx*fx
     .     + 4*polyy(15)*fy*fy*fy
     .     + 3*polyy(14)*fx*fy*fy
     .     + 2*polyy(13)*fx*fx*fy
     .     + 1*polyy(12)*fx*fx*fx
 
      dxdx0 = polyx(02)
      dxdy0 = polyx(03)
      dydx0 = polyy(02)
      dydy0 = polyy(03)
 
 
      pixarea = (dxdx *dydy  - dxdy *dydx )/
     .          (dxdx0*dydy0 - dxdy0*dydx0)
 
      return
      end
 
 
                                              
