c-------------------------------------------------------------------
c
c this routine will ouptut an i2 array if the values span more
c than (-125,125), and a b1 array if it is confined to small values
c
c
      subroutine writfits_i2ob1(FILE,pix_i2,PXDIMX,PXDIMY)
      implicit none
 
      character*(*) FILE
      integer   PXDIMX,PXDIMY
      integer*2 pix_i2(PXDIMX,PXDIMY)
 
      integer i, j
      integer imax, imin
 
      imax = pix_i2(0001,0001)
      imin = pix_i2(0001,0001)
      do i = 0001, PXDIMX
      do j = 0001, PXDIMY
         if (pix_i2(i,j).gt.imax) imax =  pix_i2(i,j)
         if (pix_i2(i,j).lt.imin) imin =  pix_i2(i,j)
         enddo
         enddo
 
      if (imin.gt.-125.and.imax.lt.125) then
          call writfits_i2b1(FILE,pix_i2,PXDIMX,PXDIMY)
          return
          endif
      call writfits_i2(FILE,pix_i2,PXDIMX,PXDIMY)
 
      return
      end
 
                                              
