c------------------------------------------
c
c this will replace delimiting characters with
c blanks to make it easier to read them in an
c unformatted way
c
      subroutine strstrip(STRING,NTOT)
      implicit none
      character*(*) STRING
      integer NTOT
      integer n
      do n = 1, NTOT
         if (STRING(n:n).eq.'(') STRING(n:n) = ' '
         if (STRING(n:n).eq.')') STRING(n:n) = ' '
         if (STRING(n:n).eq.':') STRING(n:n) = ' '
         enddo
      return
      end
 
 
                                              
