c------------------------------------------------
c
c distill info from filename
c
      subroutine distinfo(STRo,VCOL,VMIN,VMAX)
      implicit none
      character*19 STRo
      character*19 STR
      integer VCOL
      real    VMIN, VMAX
      STR = STRo
      call strstrip(STR,19)
      read(STR,*,end=83) VCOL,VMIN,VMAX
 83   continue
      return
      end
 
                                              
