c-------------------------------------------------
c
c
c
      integer function strend(stringNNN,NNN)
      implicit none
 
      character*80 stringNNN
      integer      NNN
 
      integer i
 
      strend = NNN
      do i = NNN-1, 1, -1
         if (strend.eq.NNN.and.stringNNN(i:i).ne.' ') strend = i
         enddo
 
      return
      end
 
 
                                              
