      subroutine cosort2ri(vl,nl,NTOT)
      implicit none
 
      real    vl(*)
      integer nl(*)
      integer NTOT
 
      integer n, nit
      logical change
 
      nit = 0
  1   continue
      change = .false.
      nit = nit + 1
      do n = NTOT-1, 1, -1
         if (vl(n).gt.vl(n+1)) then
            call swap(vl(n),vl(n+1))
            call swip(nl(n),nl(n+1))
            change = .true.
            endif
         enddo
      if (change.and.nit.lt.NTOT) goto 1
 
      return
      end
 
      subroutine cosort2di(vl,nl,NTOT)
      implicit none
 
      real*8 vl(*)
      integer nl(*)
      integer NTOT
 
      integer n, nit
      logical change
 
      nit = 0
  1   continue
      change = .false.
      nit = nit + 1
      do n = NTOT-1, 1, -1
         if (vl(n).gt.vl(n+1)) then
            call swdp(vl(n),vl(n+1))
            call swip(nl(n),nl(n+1))
            change = .true.
            endif
         enddo
      if (change.and.nit.lt.NTOT) goto 1
 
      return
      end
 
                                              
