c*********************************************
                                              
 
 
c
c
c this copies the contents of list (xi,yi,mi)
c into the list (xo,yo,mo), but does so in order
c of increasing mo; it only does this for the
c brightest NMAX stars.
c
c
 
      subroutine ord_copy(xi,yi,mi,NIN,xo,yo,mo,NMAX)
      implicit none
      real*8  xi(*), yi(*), mi(*)
      integer NIN
      real*8  xo(*), yo(*), mo(*)
      integer NMAX
 
      integer n, k
      real*8  mmin
      integer nmin
 
      do n = 1, NIN
         xo(n) = xi(n)
         yo(n) = yi(n)
         mo(n) = mi(n)
         enddo
 
      do n = 1, NMAX
         nmin = n
         mmin = mo(n)
         do k = n+1,NIN
            if (mo(k).lt.mmin) then
               nmin = k
               mmin = mo(k)
               endif
            enddo
         call swdp(xo(n),xo(nmin))
         call swdp(yo(n),yo(nmin))
         call swdp(mo(n),mo(nmin))
         enddo
 
      return
      end
 
 
 
 
 
 
c------------------------------------------------
c
c this copies the contents of list (xi,yi,mi)
c into the list (xo,yo,mo), but does so in order
c of increasing mo.
c
c------------------------------------------------
 
 
      subroutine ord_copyX(xi,yi,mi,NIN,xo,yo,mo,NMAX)
      implicit none
      real*8 xi(*), yi(*), mi(*)
      integer NIN
      real*8 xo(*), yo(*), mo(*)
      integer NMAX
 
      integer next(_NSTMAX_)
      integer n, k, ktot, nnow
      integer nstart
 
 
      nstart  = 1
      ktot    = 1
      do n = 2, NIN
         if (mi(n).lt.mi(nstart)) then
            next(n) = nstart
            nstart  = n
            if (ktot.lt._NMATMX_) ktot = ktot + 1
            goto 1
            endif
         nnow = nstart
         do k = 2, ktot-1
            if (mi(n).lt.mi(next(nnow))) then
               next(n)    = next(nnow)
               next(nnow) = n
               if (ktot.lt._NMATMX_) ktot = ktot + 1
               goto 1
               endif
            nnow = next(nnow)
            enddo
         if (ktot.lt._NMATMX_) then
            next(nnow) = n
            ktot = ktot + 1
            endif
  1      continue
         enddo
 
      nnow = nstart
      do k = 1, ktot
         xo(k) = xi(nnow)
         yo(k) = yi(nnow)
         mo(k) = mi(nnow)
         nnow = next(nnow)
         enddo
 
      return
      end
                                              
