c--------------------------------------
c
c bubble-sorts a real*4 list into ascending order
c
      subroutine rbubble(r1,NTOT)
      implicit none
      real r1(*)
      real temp
      integer NTOT
      integer n
      logical change
 777  continue
      change = .false.
      do n = 1, NTOT-1
         if (r1(n).gt.r1(n+1)) then
            temp = r1(n)
            r1(n) = r1(n+1)
            r1(n+1) = temp
            change = .true.
            endif
         enddo
      if (change) goto 777
      end
 
c--------------------------------------
c
c bubble-sorts a real*8 list into ascending order
c
      subroutine dbubble(r1,NTOT)
      implicit none
      real*8 r1(*)
      integer NTOT
      integer n
      real*8 temp
      logical change
 777  continue
      change = .false.
      do n = 1, NTOT-1
         if (r1(n).gt.r1(n+1)) then
            temp = r1(n)
            r1(n) = r1(n+1)
            r1(n+1) = temp
            change = .true.
            endif
         enddo
      if (change) goto 777
      end
 
 
 
 
 
 
c-----------------------------------------------------------
c
c this routine will take the x and y arrays
c of peaks (one in each image...) and will find
c the N (1st test: 5) closest and will analyze
c these 5 to produce an average/sigma.  There will
c of course be a bias in this result, but what I
c am doing here is essentially a MODE in 2 dimensions.
c
c I'll carry along the mag info so that I can average
c that for the same reported peaks
c
c
c NTOT : tot number of measts
c NUSE : the number included in the initial "mode"
c        finding (the closest NUSE...)
c NUSED: the actual number included (>=NUSE); I
c        will include those further and further
c        out provided they are consistent with
c        the inner points
c
 
      subroutine barsig2e(xl,yl,ml,ql,el,NTOT,
     .                    xbar,ybar,mbar,qbar,ebar,
     .                    xsig,ysig,msig,qsig,esig,
     .                    NMIN,NUSED,
     .                    asig,bsig,ul,DKEEP)
      implicit none
 
      integer NTOT
      real*8  xl(NTOT)
      real*8  yl(NTOT)
      real*8  ml(NTOT)
      real*8  ql(NTOT)
      real*8  el(NTOT)
      real*8  xbar, ybar, mbar, qbar, ebar
      real*8  xsig, ysig, msig, qsig, esig
      integer NMIN, NUSED
      real*8  asig, bsig
      integer ul(NTOT)
      integer n
      real*8  xsum, ysum, msum, qsum
      real*8  asum, bsum
      real*8  dsig
      real*8  dmax,dmaxx
      integer nmax
      real*8  DKEEP
 
      real*8 xbarx, ybarx
      real*8 xsigx, ysigx, dsigx
 
      real dx, dy, dd
      integer wsum, wsumx
 
 
      xbar = 0.
      ybar = 0.
      mbar = 0.
      qbar = 0.
      ebar = 1.
      xsig = 1.
      ysig = 1.
      msig = 1.
      qsig = 1.
      esig = 1.
      NUSED = 0
      if (NTOT.lt.1)    return
      if (NMIN.gt.NTOT) return
 
      if (NTOT.eq.1) then
         xbar = xl(1)
         ybar = yl(1)
         mbar = ml(1)
         qbar = ql(1)
         ebar = el(1)
         NUSED = 1
         return
         endif
 
      if (NTOT.eq.2) then
         xbar = (xl(1)+xl(2))/2
         ybar = (yl(1)+yl(2))/2
         mbar = (ml(1)+ml(2))/2
         qbar = (ql(1)+ql(2))/2
         ebar = (el(1)+el(2))/2
         xsig = abs(xl(1)-xl(2))
         ysig = abs(yl(1)-yl(2))
         msig = abs(ml(1)-ml(2))
         qsig = abs(ql(1)-ql(2))
         esig = abs(el(1)-el(2))
         NUSED = 2
         return
         endif
 
      if (NMIN.gt.NTOT) call bail('BIG PROBLEM')
      if (NTOT.gt.1000) call bail('QQUIT')
 
      do n = 1, NTOT
         ul(n) = 1
         enddo
 
      xbar = 000
      ybar = 000
      dsig = 9e9
      dmax = 9e9
  1   continue
 
      xsum = 0.
      ysum = 0.
      msum = 0.
      qsum = 0.
      wsum = 0.
      do n = 1, NTOT
         xsum = xsum + ul(n)*xl(n)
         ysum = ysum + ul(n)*yl(n)
         msum = msum + ul(n)*ml(n)
         qsum = qsum + ul(n)*ql(n)
         wsum = wsum + ul(n)
         enddo
      if (wsum.lt.2) then
         xbar = 0.
         ybar = 0.
         mbar = 0.
         xsig = 1.
         ysig = 1.
         msig = 1.
         qsig = 1.
         return
         endif
      xbar = xsum/wsum
      ybar = ysum/wsum
      mbar = msum/wsum
      qbar = qsum/wsum
 
      xsum = 0.
      ysum = 0.
      msum = 0.
      qsum = 0.
      asum = 0.
      bsum = 0.
      dmax = 0.
      nmax = 0
      do n = 1, NTOT
         xsum = xsum + ul(n)*(xl(n)-xbar)**2
         ysum = ysum + ul(n)*(yl(n)-ybar)**2
         msum = msum + ul(n)*(ml(n)-mbar)**2
         qsum = msum + ul(n)*(ql(n)-qbar)**2
         asum = asum + ul(n)*((xl(n)-xbar+yl(n)-ybar)/1.41421)**2
         bsum = bsum + ul(n)*((xl(n)-xbar-yl(n)+ybar)/1.41421)**2
         dx = xl(n)-xbar
         dy = yl(n)-ybar
         dd = sqrt(dx**2+dy**2)
         if (dd.gt.dmax.and.ul(n).eq.1) then
            dmax = dd
            nmax = n
            endif
         enddo
      xsig = sqrt(xsum/(wsum-1))
      ysig = sqrt(ysum/(wsum-1))
      asig = sqrt(asum/(wsum-1))
      bsig = sqrt(bsum/(wsum-1))
      msig = sqrt(msum/(wsum-1))
      qsig = sqrt(qsum/(wsum-1))
      dsig = sqrt(xsig**2+ysig**2)
 
      xsum = 0.
      ysum = 0.
      wsumx= 0.
      do n = 1, NTOT
         if (n.ne.nmax) then
            xsum = xsum + ul(n)*xl(n)
            ysum = ysum + ul(n)*yl(n)
            wsumx= wsumx+ ul(n)
            endif
         enddo
      xbarx = xsum/wsumx
      ybarx = ysum/wsumx
      dmaxx = sqrt((xl(NMAX)-xbarx)**2+(yl(NMAX)-ybarx)**2)
      xsum = 0.
      ysum = 0.
      do n = 1, NTOT
         if (n.ne.nmax) then
            xsum = xsum + ul(n)*(xl(n)-xbarx)**2
            ysum = ysum + ul(n)*(yl(n)-ybarx)**2
            endif
         enddo
      xsigx = sqrt(xsum/(wsumx-1))
      ysigx = sqrt(ysum/(wsumx-1))
      dsigx = sqrt(xsigx**2+ysigx**2)
 
 
c 7/20/2007: the 4*2dsig was waaaay too generous
c
c     if (dmaxx.gt.4.00*dsigx.and.
      if (dmaxx.gt.DKEEP.and.
     .    dmaxx.gt.3.00*dsigx.and.
     .    wsum.gt.NMIN.and.
     .    nmax.gt.0) then
c        print*,'REJECT! '
         ul(nmax) = 0
         goto 1
         endif
 
      NUSED = wsum
 
 
c     if (.not.(xbar.gt.  0.0)) xbar = 0.000
c     if (.not.(ybar.gt.  0.0)) ybar = 0.000
      if (.not.(mbar.gt.-99.0)) mbar = 0.000
      if (.not.(qbar.gt. -0.0)) qbar = 9.999
      if (.not.(xsig.lt.  9.0)) xsig = 9.999
      if (.not.(ysig.lt.  9.0)) ysig = 9.999
      if (.not.(msig.lt.  9.0)) msig = 9.999
      if (.not.(qsig.lt.  9.0)) qsig = 9.999
      if (.not.(asig.lt.  9.0)) asig = 9.999
      if (.not.(bsig.lt.  9.0)) bsig = 9.999
 
 
      return
      end
 
 
 
c-----------------------------------------------------------
c
c this routine will take the x and y arrays
c of peaks (one in each image...) and will find
c the N (1st test: 5) closest and will analyze
c these 5 to produce an average/sigma.  There will
c of course be a bias in this result, but what I
c am doing here is essentially a MODE in 2 dimensions.
c
c I'll carry along the mag info so that I can average
c that for the same reported peaks
c
c
c NTOT : tot number of measts
c NUSE : the number included in the initial "mode"
c        finding (the closest NUSE...)
c NUSED: the actual number included (>=NUSE); I
c        will include those further and further
c        out provided they are consistent with
c        the inner points
c
 
      subroutine barsig2(xl,yl,ml,ql,NTOT,
     .                   xbar,ybar,mbar,qbar,
     .                   xsig,ysig,msig,qsig,
     .                   NMIN,NUSED,
     .                   asig,bsig,wl,DKEEP)
      implicit none
 
      integer NTOT
      real*8 xl(NTOT)
      real*8 yl(NTOT)
      real*8 ml(NTOT)
      real*8 ql(NTOT)
      real*8 xbar, ybar, mbar, qbar
      real*8 xsig, ysig, msig, qsig
      integer NMIN, NUSED
      real*8 asig, bsig
      integer wl(NTOT)
      integer n
      real*8 xsum, ysum, msum, qsum
      real*8 asum, bsum
      real*8 dsig
      real*8  dmax,dmaxx
      integer nmax
      real*8  DKEEP
 
      real*8 xbarx, ybarx
      real*8 xsigx, ysigx, dsigx
 
      real dx, dy, dd
      integer wsum, wsumx
 
 
      xbar = 0.
      ybar = 0.
      mbar = 0.
      qbar = 0.
      xsig = 1.
      ysig = 1.
      msig = 1.
      qsig = 1.
      NUSED = 0
      if (NTOT.lt.1)    return
      if (NMIN.gt.NTOT) return
 
      if (NTOT.eq.1) then
         xbar = xl(1)
         ybar = yl(1)
         mbar = ml(1)
         qbar = ql(1)
         NUSED = 1
         return
         endif
 
      if (NTOT.eq.2) then
         xbar = (xl(1)+xl(2))/2
         ybar = (yl(1)+yl(2))/2
         mbar = (ml(1)+ml(2))/2
         qbar = (ql(1)+ql(2))/2
         xsig = abs(xl(1)-xl(2))
         ysig = abs(yl(1)-yl(2))
         msig = abs(ml(1)-ml(2))
         qsig = abs(ql(1)-ql(2))
         NUSED = 2
         return
         endif
 
      if (NMIN.gt.NTOT) call bail('BIG PROBLEM')
      if (NTOT.gt.1000) call bail('QQUIT')
 
      do n = 1, NTOT
         wl(n) = 1
         enddo
 
      xbar = 000
      ybar = 000
      dsig = 9e9
      dmax = 9e9
  1   continue
 
      xsum = 0.
      ysum = 0.
      msum = 0.
      qsum = 0.
      wsum = 0.
      do n = 1, NTOT
         xsum = xsum + wl(n)*xl(n)
         ysum = ysum + wl(n)*yl(n)
         msum = msum + wl(n)*ml(n)
         qsum = qsum + wl(n)*ql(n)
         wsum = wsum + wl(n)
         enddo
      if (wsum.lt.2) then
         xbar = 0.
         ybar = 0.
         mbar = 0.
         xsig = 1.
         ysig = 1.
         msig = 1.
         qsig = 1.
         return
         endif
      xbar = xsum/wsum
      ybar = ysum/wsum
      mbar = msum/wsum
      qbar = qsum/wsum
 
      xsum = 0.
      ysum = 0.
      msum = 0.
      qsum = 0.
      asum = 0.
      bsum = 0.
      dmax = 0.
      nmax = 0
      do n = 1, NTOT
         xsum = xsum + wl(n)*(xl(n)-xbar)**2
         ysum = ysum + wl(n)*(yl(n)-ybar)**2
         msum = msum + wl(n)*(ml(n)-mbar)**2
         qsum = msum + wl(n)*(ql(n)-qbar)**2
         asum = asum + wl(n)*((xl(n)-xbar+yl(n)-ybar)/1.41421)**2
         bsum = bsum + wl(n)*((xl(n)-xbar-yl(n)+ybar)/1.41421)**2
         dx = xl(n)-xbar
         dy = yl(n)-ybar
         dd = sqrt(dx**2+dy**2)
         if (dd.gt.dmax.and.wl(n).eq.1) then
            dmax = dd
            nmax = n
            endif
         enddo
      xsig = sqrt(xsum/(wsum-1))
      ysig = sqrt(ysum/(wsum-1))
      asig = sqrt(asum/(wsum-1))
      bsig = sqrt(bsum/(wsum-1))
      msig = sqrt(msum/(wsum-1))
      qsig = sqrt(qsum/(wsum-1))
      dsig = sqrt(xsig**2+ysig**2)
 
      xsum = 0.
      ysum = 0.
      wsumx= 0.
      do n = 1, NTOT
         if (n.ne.nmax) then
            xsum = xsum + wl(n)*xl(n)
            ysum = ysum + wl(n)*yl(n)
            wsumx= wsumx+ wl(n)
            endif
         enddo
      xbarx = xsum/wsumx
      ybarx = ysum/wsumx
      dmaxx = sqrt((xl(NMAX)-xbarx)**2+(yl(NMAX)-ybarx)**2)
      xsum = 0.
      ysum = 0.
      do n = 1, NTOT
         if (n.ne.nmax) then
            xsum = xsum + wl(n)*(xl(n)-xbarx)**2
            ysum = ysum + wl(n)*(yl(n)-ybarx)**2
            endif
         enddo
      xsigx = sqrt(xsum/(wsumx-1))
      ysigx = sqrt(ysum/(wsumx-1))
      dsigx = sqrt(xsigx**2+ysigx**2)
 
 
c 7/20/2007: the 4*2dsig was waaaay too generous
c
c     if (dmaxx.gt.4.00*dsigx.and.
      if (dmaxx.gt.DKEEP.and.
     .    dmaxx.gt.2.00*dsigx.and.
     .    wsum.gt.NMIN.and.
     .    nmax.gt.0) then
c        print*,'REJECT! '
         wl(nmax) = 0
         goto 1
         endif
 
      NUSED = wsum
 
 
c     if (.not.(xbar.gt.  0.0)) xbar = 0.000
c     if (.not.(ybar.gt.  0.0)) ybar = 0.000
      if (.not.(mbar.gt.-99.0)) mbar = 0.000
      if (.not.(qbar.gt. -0.0)) qbar = 9.999
      if (.not.(xsig.lt.  9.0)) xsig = 9.999
      if (.not.(ysig.lt.  9.0)) ysig = 9.999
      if (.not.(msig.lt.  9.0)) msig = 9.999
      if (.not.(qsig.lt.  9.0)) qsig = 9.999
      if (.not.(asig.lt.  9.0)) asig = 9.999
      if (.not.(bsig.lt.  9.0)) bsig = 9.999
 
 
      return
      end
 
 
 
 
