      integer function pk_mcpe(pk_map,ix,iy)
      implicit none
      integer*2 pk_map(_PIXDIM_,_PIXDIM_)
      integer ix, iy
      integer ii, jj
      integer iadd
 
      pk_mcpe = 0
      do ii = ix-1,ix+1
      do jj = iy-1,iy+1
         if (ix.ge.1.and.ix.le.(_PIXDIM_).and.
     .       iy.ge.1.and.iy.le.(_PIXDIM_)) then
             pk_mcpe = pk_mcpe + pk_map(ii,jj)
             endif
         enddo
         enddo
 
      return
      end
 
 
      real function pk_mapr(pk_map,ix,iy)
      implicit none
      integer*2 pk_map(_PIXDIM_,_PIXDIM_)
      integer ix, iy
 
      pk_mapr = 0
 
      pk_mapr = pk_map(ix,iy)
      if (pk_mapr.lt.0) pk_mapr = pk_mapr + 256
 
      return
      end
 
      real function CTE_YM(yr,mr)
      implicit none
      real*8 yr
      real*8 mr
 
      integer i
      real    r, f
      real ctel(14)
      data ctel/
c         1      2      3      4      5      6      7
     .  0.100, 0.100, 0.100, 0.100, 0.100, 0.075, 0.060,
     .  0.050, 0.040, 0.030, 0.020, 0.015, 0.010, 0.010/
c         8      9     10     11     12     13     14
      real SCL
 
      r = -mr
      if (r.gt.13.999) r = 13.999
      if (r.lt.01.001) r =  1.001
      i = int(r)
      f = r-i
 
      SCL = ctel(i) + f*(ctel(i+1)-ctel(i))
      if (yr.gt.2048) CTE_YM = -(4096-yr)/2048.*SCL
      if (yr.le.2048) CTE_YM =       (yr)/2048.*SCL
 
      return
      end
 
 
      subroutine purify(INSTRING)
      implicit none
 
      character*200 INSTRING
 
      integer i
 
      do i = 001, 200
         if (INSTRING(i:i).ne.' '.and.
     .       INSTRING(i:i).ne.'0'.and.
     .       INSTRING(i:i).ne.'1'.and.
     .       INSTRING(i:i).ne.'2'.and.
     .       INSTRING(i:i).ne.'3'.and.
     .       INSTRING(i:i).ne.'4'.and.
     .       INSTRING(i:i).ne.'5'.and.
     .       INSTRING(i:i).ne.'6'.and.
     .       INSTRING(i:i).ne.'7'.and.
     .       INSTRING(i:i).ne.'8'.and.
     .       INSTRING(i:i).ne.'9'.and.
     .       INSTRING(i:i).ne.'.'.and.
     .       INSTRING(i:i).ne.'-') INSTRING(i:i) = '0'
         enddo
 
      return
      end
 
 
c-----------------------------------------------
c
c reports whether a point is inside a convex
c polygon
c
      logical function inside_poly(x,y,xl,yl,Ns)
      implicit none
 
      real*8 x,y
      integer Ns
      real*8 xl(*), yl(*)
 
      integer n
      real*8  cross1
      real*8  crossN
      integer Nsu
      real*8 xlu(99), ylu(99)
 
      if (abs(Ns).gt.99) stop 'inside_poly Ns.gt.99'
 
      Nsu = Ns
      if (Nsu.lt.0) then    ! open poly, need to close
           Nsu = abs(Ns) + 1
           do N = 1, Nsu-1
              xlu(N) = xl(N)
              ylu(N) = yl(N)
              enddo
           xlu(Nsu) = xlu(1)
           ylu(Nsu) = ylu(1)
         else
           do N = 1, Ns
              xlu(N) = xl(N)
              ylu(N) = yl(N)
              enddo
         endif
 
      inside_poly = .true.
      cross1 = (x-xlu(1))*(ylu(2)-ylu(1)) - (y-ylu(1))*(xlu(2)-xlu(1))
      do n = 2, Nsu-1
           crossN = (x-xlu(N))*(ylu(N+1)-ylu(N))
     .          - (y-ylu(N))*(xlu(N+1)-xlu(N))
           if (cross1*crossN.le.0) inside_poly = .false.
           enddo
      return
      end
 
 
 
 
c-------------------------------------------------------------
c
c
c
      subroutine add_fill_poly4(xgl,ygl,pk_cvg,PIXDIM)
      implicit none
 
      real*8    xgl(5), ygl(5)
      integer   PIXDIM
      integer*2 pk_cvg(PIXDIM,PIXDIM)
 
      integer imin, imax
      integer jmin, jmax
      logical inside_poly
 
      real*8  xg, yg
      integer i, j
 
 
      imin = max(min(xgl(1),xgl(2),xgl(3),xgl(4)),000000*1.0d0)
      imax = min(max(xgl(1),xgl(2),xgl(3),xgl(4)),PIXDIM*1.0d0)
      jmin = max(min(ygl(1),ygl(2),ygl(3),ygl(4)),000000*1.0d0)
      jmax = min(max(ygl(1),ygl(2),ygl(3),ygl(4)),PIXDIM*1.0d0)
      write(*,'(10x,''   imin: '',3i8)') imin,imax,PIXDIM
      write(*,'(10x,''   jmin: '',3i8)') jmin,jmax,PIXDIM
      do i = imin, imax
      do j = jmin, jmax
         xg = i
         yg = j
         if (inside_poly(xg,yg,xgl,ygl,5).and.
     .       i.gt.0001.and.i.le.PIXDIM.and.
     .       j.gt.0001.and.j.le.PIXDIM) pk_cvg(i,j) = pk_cvg(i,j) + 1
         enddo
         enddo
 
      return
      end
 
 
 
c-----------------------------------------------------------
c
c
c
      subroutine cvg_add_c(pk_cvg,CHIPNO,PIXDIM,
     .                     AG,BG,CG,DG,Xo,Yo,Wo,Zo)
      implicit none
 
      integer   PIXDIM
      integer*2 pk_cvg(PIXDIM,PIXDIM)
 
      integer CHIPNO
      real*8 AG, BG, CG, DG
      real*8 Xo, Yo
      real*8 Wo, Zo
 
c
c master-gc frame location of chip edges...
c as a function of chip number
c
      common /xy_2pkc_/ xy_2pkc
      integer xy_2pkc(2,4,4,9)
      data    xy_2pkc /
c
c pc1 --> c=1 (not done yet)
c
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c wf2 --> c=2 (not done yet)
c
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c wf3 --> c=3 (not done yet)
c
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c wf4 --> c=4 (not done yet)
c
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c acs ---> c=5
c
     .   0040,-140, 4130,0110, 4110,2190, 0060,1885,
     .   0060,1950, 4110,2255, 4090,4260, 0110,3900,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c acsx --> c=6 (not done)
c
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c hrc --> c=7 (not done yet)
c
     .   0007,0019,    3,0901, 1010,1001, 1006, 121,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
 
c
c wfc3uvis ---> c=8
c
     .   0010,0080, 4110,0325, 4095,2375, 0023,2108,
     .   0023,2152, 4095,2425, 4080,4450, 0030,4155,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
c
c wfc3ir ---> c=9
c
     .   -049,0013, 1061,0013, 1017,1018, -059,1018,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000,
     .   0000,0000, 0000,0000, 0000,0000, 0000,0000/
 
      real*8 xcl(5), ycl(5)
      real*8 xgl(5), ygl(5)
 
      integer i, j
      integer k, p
 
 
      if (CHIPNO.le.01.or.CHIPNO.ge.10) then
         do i = 0001, PIXDIM
         do j = 0001, PIXDIM
            pk_cvg(i,j) = 1
            enddo
            enddo
         return
         endif
 
 
      do k = 1, 4
         if (xy_2pkc(1,1,k,CHIPNO).ne.0) then
            print*,' '
            write(*,'(10x,''      k:'',i1)') k
            do p = 1, 4
               xcl(p) = xy_2pkc(1,p,k,CHIPNO)
               ycl(p) = xy_2pkc(2,p,k,CHIPNO)
               enddo
            xcl(5) = xy_2pkc(1,1,k,CHIPNO)
            ycl(5) = xy_2pkc(2,1,k,CHIPNO)
            do p = 1, 5
               xgl(p) = (AG*(xcl(p)-Xo)+BG*(ycl(p)-Yo) + Wo)*(_F_)
               ygl(p) = (CG*(xcl(p)-Xo)+DG*(ycl(p)-Yo) + Zo)*(_F_)
               enddo
            do p = 1, 5
               write(*,'(10x,''      p:'',i1,4i8)')
     .                   p,int(xgl(p)),int(ygl(p)),
     .                     int(xcl(p)),int(ygl(p))
               enddo
            call add_fill_poly4(xgl,ygl,pk_cvg,PIXDIM)
            endif
         enddo
 
      return
      end
 
 
c------------------------------------
c
c routine that tweaks the y positions
c in order to improve CTE shifting
c
      subroutine doctefix_ym(yin,zin,CTE_MAG,CTE_FIX,NCTEs)
      implicit none
 
      real*8 yin
      real*8 zin
      integer NCTEs
      real   CTE_MAG(NCTEs)
      real   CTE_FIX(NCTEs)
 
      real   f
      real   fy
      real   CTE_FIX_m
      real*8 yin0
 
      integer NCTE
      integer q
 
      real dyfix
 
      yin0 = yin
 
      CTE_FIX_m = 0
 
      if (NCTEs.eq.0) return
      if (zin.lt.CTE_MAG(    1)) return
      if (zin.gt.CTE_MAG(NCTEs)) return
 
      if (NCTEs.eq.1) CTE_FIX_m = CTE_FIX(1)
 
      if (NCTEs.ge.2) then
          NCTE = 0
   2      continue
          NCTE = NCTE + 1
          if (CTE_MAG(NCTE).gt.CTE_MAG(NCTE+1)) then
              print*,'CTE_FIX out of order at ',NCTE
              do q = 1, NCTEs
                 print*,q,CTE_MAG(q),CTE_FIX(q)
                 enddo
              print*,'             '
              stop 'Serious problem'
              endif
          if (zin.gt.CTE_MAG(NCTE+1).and.NCTE.lt.NCTEs-1) goto 2
          f = (zin            -CTE_MAG(NCTE))/
     .        (CTE_MAG(NCTE+1)-CTE_MAG(NCTE))
          CTE_FIX_m = CTE_FIX(NCTE)+f*(CTE_FIX(NCTE+1)
     .                                -CTE_FIX(NCTE  ))
          endif
 
      fy = 0.
      if (yin.lt.2048) then
          fy = -yin/2048
         else
          fy = + (4096-yin)/2048
         endif
 
      dyfix = 0.
      dyfix = CTE_FIX_m*fy
 
      yin = yin0 + dyfix
 
      write(76,176) yin0, yin, zin, CTE_FIX_m, fy
  176 format(1x,9f11.4)
 
      return
      end
 
 
 
c
c format should be
c
c CTEFIX( -13,0.00 ; -12,0.01 ; ...)
c
c
      subroutine ingest_ctefix(INSTRING,NCTEs,CTE_MAG,CTE_FIX)
      implicit none
 
      character*200 INSTRING
      integer       NCTEs
      real          CTE_MAG(99)
      real          CTE_FIX(99)
 
      character*25  STRING_N(99)
      integer       i, i0
      integer       NCTE
 
      if (INSTRING(1:6).ne.'CTEFIX') stop 'this is not a CTEFIX line!'
      if (INSTRING(7:7).ne.'(')      stop 'bad CTEFIX format!'
      i  = 7
      i0 = 8
      NCTEs = 0
    1 continue
      i = i + 1
      if (INSTRING(i:i).eq.';'.or.INSTRING(i:i).eq.')') then
          NCTEs = NCTEs + 1
          STRING_N(NCTEs) = INSTRING(i0:i-1)
          read(STRING_N(NCTEs),*) CTE_MAG(NCTEs),CTE_FIX(NCTEs)
c         write(*,119) NCTEs, i0, i-1, CTE_MAG(NCTEs),CTE_FIX(NCTEs),
c    .                 STRING_N(NCTEs)
c 119     format(i3,3x,2i5,3x,f8.3,1x,f8.4,1x,a25)
  118     format(i3,1x,f8.3,1x,f8.4,1x,a25)
          if (INSTRING(i:i).eq.')') goto 2
          i0 = i+1
          endif
      goto 1
    2 continue
      print*,'        '
      print*,'NCTEs = ',NCTEs
      print*,'        '
      do NCTE = 1, NCTEs
         write(*,118) NCTE, CTE_MAG(NCTE),CTE_FIX(NCTE)
         enddo
      print*,'        '
 
      return
      end
 
 
 
